const items = $input.all();

for (const item of items) {
  item.json = item.json || {};

  item.json.chatId = String(
    item.json.chatId ||
    item.json.sessionId ||
    item.json.telegramUserId ||
    '8330685521'
  );

  item.json.sessionId = String(
    item.json.sessionId ||
    item.json.chatId ||
    '8330685521'
  );

  item.json.telegramUserId = String(
    item.json.telegramUserId ||
    item.json.chatId ||
    '8330685521'
  );

  if (item.binary) {
    for (const propName of Object.keys(item.binary)) {
      const binary = item.binary[propName];

      binary.mimeType = 'audio/mpeg';
      binary.fileName = binary.fileName || 'rocket-reply.mp3';
      binary.fileExtension = binary.fileExtension || 'mp3';
    }
  }
}

return items;

// Clean Responses
// Normalise PA/Rocket output, preserve chatId and voice flags, replace n8n footer, and split long Telegram messages.

const item = $input.first().json || {};

let securityJson = {};
try {
  const securityItems = $items('Telegram UserID Security Check');
  securityJson = securityItems?.[0]?.json || {};
} catch (e) {
  securityJson = {};
}

let normalisationJson = {};
try {
  const normalisationItems = $items('Normalization');
  normalisationJson = normalisationItems?.[0]?.json || {};
} catch (e) {
  normalisationJson = {};
}

const rawText = String(
  item.telegramText ||
  item.output ||
  item.text ||
  item.response ||
  item.message ||
  item.result ||
  ''
).trim();

const chatId = String(
  item.chatId ||
  item.sessionId ||
  item.telegramUserId ||
  securityJson.chatId ||
  securityJson.sessionId ||
  securityJson.telegramUserId ||
  normalisationJson.chatId ||
  normalisationJson.sessionId ||
  normalisationJson.telegramUserId ||
  '8330685521'
).trim();

const inputType = String(
  item.inputType ||
  securityJson.inputType ||
  normalisationJson.inputType ||
  ''
).trim();

const wantsVoiceReply = Boolean(
  item.wantsVoiceReply ||
  securityJson.wantsVoiceReply ||
  normalisationJson.wantsVoiceReply ||
  inputType === 'audio'
);

function cleanTelegramText(value) {
  return String(value || '')
    .replace(/This message was sent automatically with n8n/gi, '')
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/---/g, '')
    .trim();
}

function splitTelegramText(text, maxLength = 3500) {
  const chunks = [];
  let remaining = text.trim();

  while (remaining.length > maxLength) {
    let splitAt = remaining.lastIndexOf('\n\n', maxLength);

    if (splitAt < maxLength * 0.5) {
      splitAt = remaining.lastIndexOf('\n', maxLength);
    }

    if (splitAt < maxLength * 0.5) {
      splitAt = remaining.lastIndexOf(' ', maxLength);
    }

    if (splitAt < 1) {
      splitAt = maxLength;
    }

    chunks.push(remaining.slice(0, splitAt).trim());
    remaining = remaining.slice(splitAt).trim();
  }

  if (remaining) {
    chunks.push(remaining);
  }

  return chunks;
}

const cleaned = cleanTelegramText(rawText) || 'No response was returned.';
const withFooter = `${cleaned}\n\nGG`;

const chunks = splitTelegramText(withFooter, 3500);
const total = chunks.length;

return chunks.map((chunk, index) => {
  const prefix = total > 1 ? `Part ${index + 1} of ${total}\n\n` : '';

  return {
    json: {
      chatId,
      sessionId: chatId,
      telegramUserId: chatId,
      inputType,
      wantsVoiceReply,
      output: prefix + chunk,
      telegramText: prefix + chunk,
      messagePart: index + 1,
      messagePartsTotal: total,
    },
  };
});

const allowedUserId = '8330685521';

return $input.all().map((i) => {
  const json = i.json || {};
  const message = json.message || {};

  const detectedUserId = String(
    json.telegramUserId ||
    json.sessionId ||
    json.chatId ||
    message.from?.id ||
    message.chat?.id ||
    ''
  ).trim();

  const detectedChatId = String(
    json.chatId ||
    message.chat?.id ||
    message.from?.id ||
    detectedUserId ||
    ''
  ).trim();

  const chatInput = String(
    json.chatInput ||
    json.userCommand ||
    message.caption ||
    message.text ||
    json.text ||
    ''
  ).trim();

  const originalVoiceFileId = String(
    json.originalVoiceFileId ||
    message.voice?.file_id ||
    ''
  ).trim();

  const largestPhoto = Array.isArray(message.photo)
    ? message.photo[message.photo.length - 1]
    : null;

  const documentMimeType = String(message.document?.mime_type || '');
  const documentFileName = String(message.document?.file_name || '');

  const originalImageFileId = String(
    json.originalImageFileId ||
    largestPhoto?.file_id ||
    (
      documentMimeType.startsWith('image/')
        ? message.document?.file_id
        : ''
    ) ||
    ''
  ).trim();

  const originalDocumentFileId = String(
    json.originalDocumentFileId ||
    (
      message.document?.file_id && !documentMimeType.startsWith('image/')
        ? message.document.file_id
        : ''
    ) ||
    ''
  ).trim();

  const inputType =
    originalVoiceFileId ? 'audio' :
    originalImageFileId ? 'image' :
    originalDocumentFileId ? 'file' :
    chatInput ? 'text' :
    'unknown';

  const unauthorized =
    detectedUserId !== allowedUserId &&
    detectedChatId !== allowedUserId;

  return {
    json: {
      ...json,
      unauthorized,
      chatId: detectedChatId || detectedUserId || allowedUserId,
      sessionId: detectedUserId || detectedChatId || allowedUserId,
      telegramUserId: detectedUserId || allowedUserId,
      chatInput,
      userCommand: chatInput,
      inputType,
      originalVoiceFileId,
      originalImageFileId,
      originalDocumentFileId,
      documentMimeType,
      documentFileName,
      wantsVoiceReply: inputType === 'audio',
      output: unauthorized ? 'Unauthorized Telegram user.' : json.output,
      telegramText: unauthorized ? 'Unauthorized Telegram user.' : json.telegramText,
    },
    binary: i.binary,
  };
});

