const current = $input.item;

const sourceBinary = current.binary?.data || $('Get Message').item.binary?.data;

if (!sourceBinary) {
  throw new Error('No binary data found. Confirm Get Message has Download Images/Files enabled and Telegram UserID Security Check preserves binary.');
}

const now = Date.now();
const extension = String(sourceBinary.fileExtension || 'jpg').replace(/[^a-zA-Z0-9]/g, '');
const messageId = String(
  current.json.message?.message_id ||
  current.json.update_id ||
  now
).replace(/[^a-zA-Z0-9_-]/g, '');

const fileName = `telegram-image-${messageId}-${now}.${extension}`;

return {
  json: {
    ...current.json,
    imageFileName: fileName,
  },
  binary: {
    data: {
      ...sourceBinary,
      fileName,
      fileExtension: extension,
      mimeType: sourceBinary.mimeType || 'image/jpeg',
    },
  },
};

const text = (
  $json.userCommand ||
  $json.chatInput ||
  $json.message?.text ||
  ''
).toLowerCase();

let targetAgent = 'rocket';

if (/\bgroot\b/.test(text)) targetAgent = 'groot';
else if (/\bdrax\b/.test(text)) targetAgent = 'drax';
else if (/\bgamora\b/.test(text)) targetAgent = 'gamora';
else if (/\byondu\b/.test(text)) targetAgent = 'yondu';
else if (/\bnebula\b/.test(text)) targetAgent = 'nebula';

return [{
  json: {
    ...$json,
    targetAgent,
  }
}];

