// n8n Code node
// Mode: Run Once for All Items
// Purpose: Take extracted Google Drive markdown text, attach metadata, chunk it, and prepare for Qdrant indexing.

const items = $input.all();

// Pull metadata from earlier workflow nodes.
// These node names must match your workflow.
const metadataSource = $('Set File Metadata').first().json || {};
const driveFile = $('Find Google Drive File').first().json || {};

const output = [];

// Shared master files fallback rules.
// This protects you if Merge drops metadata.
function inferSharedDocType(fileName) {
  const name = String(fileName || '').trim();

  if (name === 'ROUTING.md') return 'routing';
  if (name === 'AGENTY_REGISTRY.md') return 'registry';
  if (name === 'USER.md') return 'user_profile';
  if (name === 'PROJECTS.md') return 'projects';

  return 'unknown';
}

function inferAgentIdFromFile(fileName, folderPath) {
  const name = String(fileName || '').trim();
  const path = String(folderPath || '').toLowerCase();

  // Shared files
  if (['ROUTING.md', 'AGENTY_REGISTRY.md', 'USER.md', 'PROJECTS.md'].includes(name)) {
    return 'shared';
  }

  // Agent folders
  if (path.includes('daily_brief_nebula')) return 'dailybrief';
  if (path.includes('career_drax')) return 'career';
  if (path.includes('entrepreneur_groot')) return 'entrepreneur';
  if (path.includes('pa_rocket')) return 'rocket';
  if (path.includes('social_media_yondu')) return 'socialmedia';
  if (path.includes('coding_gamora')) return 'coding';

  return 'unknown';
}

function inferAgentNameFromId(agentId) {
  const id = String(agentId || '').trim();

  const names = {
    shared: 'Shared',
    dailybrief: 'Nebula',
    career: 'Drax',
    entrepreneur: 'Groot',
    rocket: 'Rocket',
    socialmedia: 'Yondu',
    coding: 'Gamora',
  };

  return names[id] || 'Unknown';
}

function inferDocTypeFromAgentFile(fileName) {
  const name = String(fileName || '').toLowerCase();

  if (name.includes('identity')) return 'identity';
  if (name.includes('soul')) return 'soul';
  if (name.includes('tools')) return 'tools';
  if (name.includes('daily') || name.includes('brief')) return 'daily_brief_playbook';
  if (name.includes('routing')) return 'routing';
  if (name.includes('registry')) return 'registry';
  if (name.includes('project')) return 'projects';
  if (name.includes('user')) return 'user_profile';

  return 'unknown';
}

function normaliseRoutingTags(value) {
  if (Array.isArray(value)) {
    return value.map(t => String(t).trim()).filter(Boolean);
  }

  return String(value || '')
    .split(',')
    .map(t => t.trim())
    .filter(Boolean);
}

function getTextFromItem(input) {
  // Extract from common n8n file/text shapes.
  return String(
    input.text ||
    input.content ||
    input.body ||
    input.data ||
    input.markdown ||
    ''
  ).trim();
}

function chunkText(text, chunkSize = 1200, overlap = 150) {
  const chunks = [];
  let start = 0;

  while (start < text.length) {
    let end = start + chunkSize;

    if (end < text.length) {
      const headingBreak = text.lastIndexOf('\n## ', end);
      const paragraphBreak = text.lastIndexOf('\n\n', end);
      const lineBreak = text.lastIndexOf('\n', end);
      const sentenceBreak = text.lastIndexOf('. ', end);

      if (headingBreak > start + 500) {
        end = headingBreak;
      } else if (paragraphBreak > start + 500) {
        end = paragraphBreak;
      } else if (lineBreak > start + 500) {
        end = lineBreak;
      } else if (sentenceBreak > start + 500) {
        end = sentenceBreak + 1;
      }
    }

    const chunk = text.slice(start, end).trim();

    if (chunk.length > 0) {
      chunks.push(chunk);
    }

    const nextStart = end - overlap;
    start = nextStart <= start ? end : nextStart;
  }

  return chunks;
}

for (const item of items) {
  const input = item.json || {};

  const text = getTextFromItem(input);

  const fileName =
    metadataSource.source_file ||
    metadataSource.file_name ||
    driveFile.name ||
    input.source_file ||
    input.file_name ||
    input.name ||
    'unknown';

  const folderPath =
    metadataSource.folder_path ||
    input.folder_path ||
    (
      ['ROUTING.md', 'AGENTY_REGISTRY.md', 'USER.md', 'PROJECTS.md'].includes(fileName)
        ? 'Projects/n8n/Shared files'
        : 'unknown'
    );

  const inferredDocTypeFromShared = inferSharedDocType(fileName);
  const inferredDocTypeFromAgent = inferDocTypeFromAgentFile(fileName);

  const docType =
    metadataSource.doc_type ||
    input.doc_type ||
    (inferredDocTypeFromShared !== 'unknown' ? inferredDocTypeFromShared : inferredDocTypeFromAgent);

  const agentId =
    metadataSource.agent_id ||
    input.agent_id ||
    inferAgentIdFromFile(fileName, folderPath);

  const agentName =
    metadataSource.agent_name ||
    input.agent_name ||
    inferAgentNameFromId(agentId);

  const scope =
    metadataSource.scope ||
    input.scope ||
    (agentId === 'shared' ? 'shared' : 'agent');

  const collection =
    metadataSource.collection ||
    input.collection ||
    'assistant-core';

  const topic =
    metadataSource.topic ||
    input.topic ||
    (
      docType === 'routing' ? 'agent routing' :
      docType === 'registry' ? 'agent registry' :
      docType === 'user_profile' ? 'user context' :
      docType === 'projects' ? 'projects' :
      ''
    );

  const routingTags = normaliseRoutingTags(
    metadataSource.routing_tags ||
    input.routing_tags ||
    (
      docType === 'routing'
        ? 'orchestration,routing,agents,intent,delegation'
        : ''
    )
  );

  const priority =
    metadataSource.priority ||
    input.priority ||
    (
      ['routing', 'registry', 'user_profile', 'daily_brief_playbook'].includes(docType)
        ? 'high'
        : 'medium'
    );

  const sourceFileId =
    driveFile.id ||
    metadataSource.source_file_id ||
    input.source_file_id ||
    input.id ||
    null;

  if (!text) {
    throw new Error(
      `No text found for file "${fileName}". Check that Extract from File outputs a json.text field.`
    );
  }

  const chunks = chunkText(text, 1200, 150);
  const now = new Date().toISOString();

  chunks.forEach((chunk, index) => {
    output.push({
      json: {
        text: chunk,
        metadata: {
          source_system: 'google_drive',
          workspace: 'n8n',
          collection,

          scope,
          agent_id: agentId,
          agent_name: agentName,

          file_name: fileName,
          file_type: 'md',
          doc_type: docType,

          folder_path: folderPath,
          source_file_id: sourceFileId,

          topic,
          routing_tags: routingTags,
          priority,

          chunk_index: index,
          chunk_total: chunks.length,
          indexed_at: now,
        },
      },
    });
  });
}

return output;

const raw = items[0]?.json ?? {};
const body = raw.body ?? raw;

function first(...values) {
  for (const value of values) {
    if (value === undefined || value === null) continue;
    if (typeof value === 'string' && value.trim() === '') continue;
    return value;
  }
  return '';
}

const tradeType = String(first(body.trade_type, body.trade, body.service_type, 'electrical')).toLowerCase();
const jobDescription = first(body.job_description, body.description, body.job_request, body.issue, '');
const location = first(body.customer_suburb, body.suburb, body.address, body.location, '');
const urgency = first(body.urgency, 'normal');
const requestedAtMs = Date.now();
const requestedAt = new Date(requestedAtMs).toISOString();

return [{
  json: {
    requested_at: requestedAt,
    requested_at_ms: requestedAtMs,
    target_sla_ms: Number(first(body.target_sla_ms, 5000)) || 5000,
    lead_id: first(body.lead_id, body.reference, ''),
    quote_id: first(body.quote_id, ''),
    trade_type: tradeType,
    job_description: jobDescription,
    customer_suburb: location,
    urgency,
    materials_cost: first(body.materials_cost, body.estimated_materials_cost, ''),
    labour_hours: first(body.labour_hours, body.estimated_labour_hours, ''),
    callout_fee: first(body.callout_fee, 150),
    source_agent: 'sally',
    source_tool: 'price_estimate',
  },
}];

const rec = items[0]?.json ?? {};
const original = $('Normalise Sally Price Request').first().json || {};
const requestedAtMs = Number(original.requested_at_ms || Date.now());
const respondedAtMs = Date.now();
const responseMs = Math.max(0, respondedAtMs - requestedAtMs);
const targetSlaMs = Number(original.target_sla_ms || 5000);
const low = Number(rec.recommended_low ?? rec.price_band_low ?? 0);
const high = Number(rec.recommended_high ?? rec.price_band_high ?? 0);
const callout = Number(rec.callout_fee ?? 150);
const fallback = !low || !high;

const lowOut = fallback ? 150 : low;
const highOut = fallback ? 350 : high;

return [{
  json: {
    estimate_available: true,
    currency: 'AUD',
    price_band_low: lowOut,
    price_band_high: highOut,
    indicative_price_band: rec.indicative_price_band || `$${lowOut}-$${highOut}`,
    callout_fee: callout,
    confidence_label: rec.confidence_label || (fallback ? 'low' : 'medium'),
    confidence_score: rec.confidence_score ?? null,
    evidence_count: rec.evidence_count ?? 0,
    recommendation_key: rec.recommendation_key || null,
    pricing_note: 'This is an indicative estimate only. Final pricing must be confirmed by the tradie before any work begins.',
    customer_message: rec.customer_message || `The indicative estimate is $${lowOut}-$${highOut}. The tradie will confirm the final quote before any work begins.`,
    risk_flags: rec.risk_flags || [],
    assumptions: rec.assumptions || [
      'Indicative estimate only',
      'Final price confirmed by tradie before work begins',
    ],
    source_agent: 'Nelly',
    source_request_agent: original.source_agent || 'sally',
    requested_at: original.requested_at || new Date(requestedAtMs).toISOString(),
    responded_at: new Date(respondedAtMs).toISOString(),
    response_ms: responseMs,
    target_sla_ms: targetSlaMs,
    quote_sla_met: responseMs <= targetSlaMs,
    quote_sla_label: responseMs <= targetSlaMs ? 'on_call_sla_met' : 'on_call_sla_missed',
  },
}];

const result = items[0]?.json ?? {};

function sql(value) {
  if (value === undefined || value === null || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function num(value) {
  if (value === undefined || value === null || value === '') return 'NULL';
  const n = Number(String(value).replace(/[^0-9.\-]/g, ''));
  return Number.isFinite(n) ? String(n) : 'NULL';
}

function jsonSql(value) {
  return `'${JSON.stringify(value ?? {}).replace(/'/g, "''")}'::jsonb`;
}

const query = `
CREATE TABLE IF NOT EXISTS quote_sla_metrics (
  id uuid primary key default gen_random_uuid(),
  recommendation_key text,
  lead_id text references leads(id),
  quote_id text,
  source_agent text not null default 'sally',
  trade_type text,
  job_description text,
  requested_at timestamptz not null default now(),
  responded_at timestamptz not null default now(),
  response_ms integer,
  target_sla_ms integer not null default 5000,
  sla_met boolean,
  confidence_score numeric,
  confidence_label text,
  evidence_count integer,
  indicative_price_band text,
  status text,
  payload jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now()
);

CREATE INDEX IF NOT EXISTS idx_quote_sla_metrics_lead ON quote_sla_metrics(lead_id, created_at desc);
CREATE INDEX IF NOT EXISTS idx_quote_sla_metrics_sla ON quote_sla_metrics(sla_met, created_at desc);

INSERT INTO quote_sla_metrics (
  recommendation_key, lead_id, quote_id, source_agent, trade_type, job_description,
  requested_at, responded_at, response_ms, target_sla_ms, sla_met,
  confidence_score, confidence_label, evidence_count, indicative_price_band, status, payload
)
VALUES (
  ${sql(result.recommendation_key)},
  ${sql(result.lead_id)},
  ${sql(result.quote_id)},
  ${sql(result.source_request_agent || 'sally')},
  ${sql(result.trade_type)},
  ${sql(result.job_description)},
  ${sql(result.requested_at)},
  ${sql(result.responded_at)},
  ${num(result.response_ms)},
  ${num(result.target_sla_ms || 5000)},
  ${result.quote_sla_met ? 'true' : 'false'},
  ${num(result.confidence_score)},
  ${sql(result.confidence_label)},
  ${num(result.evidence_count)},
  ${sql(result.indicative_price_band)},
  ${sql(result.quote_sla_label)},
  ${jsonSql(result)}
);

INSERT INTO workflow_events (entity_type, entity_id, event_type, payload)
VALUES ('price_recommendation', ${sql(result.recommendation_key || result.lead_id || 'unknown')}, 'quote_sla_measured', ${jsonSql(result)});

SELECT jsonb_build_object('success', true, 'quote_sla_met', ${result.quote_sla_met ? 'true' : 'false'}, 'response_ms', ${num(result.response_ms)}) AS quote_sla_saved;
`;

return [{ json: { ...result, sql: query } }];

const hasBusyEvent = items.some((item) => item.json && typeof item.json.id === 'string' && item.json.id.trim() !== '');

return [
  {
    json: hasBusyEvent
      ? {
          available: false,
          recommended_slot: 'Thursday between 2:00 PM and 4:00 PM',
          alternative_slot: 'Friday between 9:00 AM and 11:00 AM',
          booking_note: 'The requested window appears busy. Offer the recommended slot and confirm before booking.',
        }
      : {
          available: true,
          recommended_slot: 'Tomorrow between 10:00 AM and 12:00 PM',
          alternative_slot: 'Thursday between 2:00 PM and 4:00 PM',
          booking_note: 'This window appears available based on the current calendar. Final confirmation should still be sent by the business.',
        },
  },
